import{_ as t,c as o,o as a,ag as r}from"./chunks/framework.Bw-5EFTY.js";const u=JSON.parse('{"title":"ByteDance Specification","description":"","frontmatter":{},"headers":[],"relativePath":"packages/agent-provider-bytedance/SPEC.md","filePath":"packages/agent-provider-bytedance/SPEC.md"}'),d={name:"packages/agent-provider-bytedance/SPEC.md"};function n(i,e,c,s,l,p){return a(),o("div",null,e[0]||(e[0]=[r('<h1 id="bytedance-specification" tabindex="-1">ByteDance Specification <a class="header-anchor" href="#bytedance-specification" aria-label="Permalink to &quot;ByteDance Specification&quot;">​</a></h1><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><p>Owns ByteDance and BytePlus media provider integration for Robota SDK. Implements <code>IVideoGenerationProvider</code> from <code>@robota-sdk/agent-core</code> for Seedance video generation, including video task creation, polling, and cancellation via the BytePlus/ModelArk HTTP API.</p><h2 id="boundaries" tabindex="-1">Boundaries <a class="header-anchor" href="#boundaries" aria-label="Permalink to &quot;Boundaries&quot;">​</a></h2><ul><li>Does not own generic media contracts (<code>IVideoGenerationProvider</code>, <code>IVideoJobSnapshot</code>, <code>TProviderMediaResult</code>); those belong to <code>@robota-sdk/agent-core</code>.</li><li>Does not own DAG contracts or agent execution contracts.</li><li>Provider-specific request/response mapping and HTTP transport are fully contained in this package.</li><li>No direct dependency on other provider packages (<code>openai</code>, <code>anthropic</code>, <code>google</code>).</li></ul><h2 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h2><p>Single-class provider architecture. <code>BytedanceProvider</code> handles all HTTP communication with the BytePlus API, maps upstream responses to the canonical <code>TProviderMediaResult</code> shape, and normalizes status strings to the standard <code>IVideoJobSnapshot</code> status enum. Content payload construction supports text prompts and inline/URI image inputs.</p><h2 id="type-ownership" tabindex="-1">Type Ownership <a class="header-anchor" href="#type-ownership" aria-label="Permalink to &quot;Type Ownership&quot;">​</a></h2><p>This package is SSOT for:</p><ul><li><code>IBytedanceProviderOptions</code> -- provider configuration (API key, base URL, path templates, timeout).</li><li><code>IBytedanceCreateVideoTaskRequest</code> / <code>IBytedanceCreateVideoTaskResponse</code> -- upstream request/response shapes.</li><li><code>IBytedanceVideoTaskResponse</code> -- upstream task polling response.</li><li><code>IBytedanceApiErrorResponse</code> -- upstream error body shape.</li><li><code>TBytedanceTaskContent</code> (<code>IBytedanceTaskContentText | IBytedanceTaskContentImageUrl</code>) -- content payload union.</li></ul><h2 id="public-api-surface" tabindex="-1">Public API Surface <a class="header-anchor" href="#public-api-surface" aria-label="Permalink to &quot;Public API Surface&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Export</th><th>Kind</th><th>Description</th></tr></thead><tbody><tr><td><code>BytedanceProvider</code></td><td>class</td><td><code>IVideoGenerationProvider</code> implementation for BytePlus/ModelArk</td></tr><tr><td><code>IBytedanceProviderOptions</code></td><td>interface</td><td>Constructor configuration</td></tr><tr><td><code>TBytedanceTaskContent</code></td><td>type</td><td>Content payload discriminated union</td></tr><tr><td><code>IBytedanceCreateVideoTaskRequest</code></td><td>interface</td><td>Upstream create-task request body</td></tr><tr><td><code>IBytedanceCreateVideoTaskResponse</code></td><td>interface</td><td>Upstream create-task response body</td></tr><tr><td><code>IBytedanceVideoTaskResponse</code></td><td>interface</td><td>Upstream task-poll response body</td></tr><tr><td><code>IBytedanceApiErrorResponse</code></td><td>interface</td><td>Upstream error response body</td></tr></tbody></table><h2 id="extension-points" tabindex="-1">Extension Points <a class="header-anchor" href="#extension-points" aria-label="Permalink to &quot;Extension Points&quot;">​</a></h2><p>None. Consumers instantiate <code>BytedanceProvider</code> with <code>IBytedanceProviderOptions</code>. Path templates and cancel method can be customized via options but no abstract classes or plug-in interfaces are exposed.</p><h2 id="error-taxonomy" tabindex="-1">Error Taxonomy <a class="header-anchor" href="#error-taxonomy" aria-label="Permalink to &quot;Error Taxonomy&quot;">​</a></h2><p>All errors are returned via <code>TProviderMediaResult</code> (Result pattern, never thrown).</p><table tabindex="0"><thead><tr><th>Code</th><th>Condition</th></tr></thead><tbody><tr><td><code>PROVIDER_INVALID_REQUEST</code></td><td>Empty prompt, empty model, seed field supplied, empty image data/uri, 4xx client error</td></tr><tr><td><code>PROVIDER_AUTH_ERROR</code></td><td>HTTP 401 / 403</td></tr><tr><td><code>PROVIDER_JOB_NOT_FOUND</code></td><td>HTTP 404</td></tr><tr><td><code>PROVIDER_JOB_NOT_CANCELLABLE</code></td><td>HTTP 409</td></tr><tr><td><code>PROVIDER_RATE_LIMITED</code></td><td>HTTP 429</td></tr><tr><td><code>PROVIDER_UPSTREAM_ERROR</code></td><td>5xx, invalid JSON, missing task id, unexpected status</td></tr><tr><td><code>PROVIDER_TIMEOUT</code></td><td>Fetch aborted by timeout</td></tr></tbody></table><h2 id="class-contract-registry" tabindex="-1">Class Contract Registry <a class="header-anchor" href="#class-contract-registry" aria-label="Permalink to &quot;Class Contract Registry&quot;">​</a></h2><h3 id="interface-implementations" tabindex="-1">Interface Implementations <a class="header-anchor" href="#interface-implementations" aria-label="Permalink to &quot;Interface Implementations&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Interface</th><th>Implementor</th><th>Kind</th><th>Location</th></tr></thead><tbody><tr><td><code>IVideoGenerationProvider</code> (agents)</td><td><code>BytedanceProvider</code></td><td>production</td><td><code>src/provider.ts</code></td></tr></tbody></table><h3 id="inheritance-chains" tabindex="-1">Inheritance Chains <a class="header-anchor" href="#inheritance-chains" aria-label="Permalink to &quot;Inheritance Chains&quot;">​</a></h3><p>None. <code>BytedanceProvider</code> implements an interface directly (no abstract base class).</p><h3 id="cross-package-port-consumers" tabindex="-1">Cross-Package Port Consumers <a class="header-anchor" href="#cross-package-port-consumers" aria-label="Permalink to &quot;Cross-Package Port Consumers&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Port (Owner)</th><th>Adapter</th><th>Location</th></tr></thead><tbody><tr><td><code>IVideoGenerationProvider</code> (agents)</td><td><code>BytedanceProvider</code></td><td><code>src/provider.ts</code></td></tr></tbody></table><h2 id="test-strategy" tabindex="-1">Test Strategy <a class="header-anchor" href="#test-strategy" aria-label="Permalink to &quot;Test Strategy&quot;">​</a></h2><ul><li><strong>Unit tests</strong>: <code>provider.spec.ts</code> -- 5 test cases covering <code>createVideo</code>, <code>getVideoJob</code>, <code>cancelVideoJob</code>, HTTP error mapping (404), and status normalization. Uses <code>vi.stubGlobal(&#39;fetch&#39;, ...)</code> to mock network calls.</li><li><strong>Scenario verification</strong>: <code>pnpm scenario:verify</code> runs a dry-run example (<code>examples/example-create-video.ts</code>).</li><li><strong>Coverage gaps</strong>: No integration tests against live API; no tests for image input payloads or timeout paths.</li></ul>',26)]))}const m=t(d,[["render",n]]);export{u as __pageData,m as default};
